const express = require('express');
const multer  = require('multer');  //middleware for handling multipart/form-data, useful for uploading files from user interface (like dropbox) in nodejs applications using MongoDB as database. It's a library to handle file upload and store them into your server(Mongo DB).
const fs = require('fs');  //require 'node:fs', it includes methods like readFile, writeFiles etc.. of the Node JS File System module which can be used in our application for handling files. Used when saving uploaded images or any file to a database using multer middleware at uploads/images
const shortid = require('shortid'); //a simple globally unique identifier (UUID) library designed specifically around minimizing duplication and increasing uniqueness across different contexts by generating random id's for our image files in the db. It simplifies handling of file names as they need not to be long or complicated then it generates shorter, more readable strings which are suitable
const upload = multer({  //Middleware function that creates an object with properties and methods available on req body (form data) such a method for accepting multiple files. This also handles any possible errors while performing the file save operation by returning 'err' if something went wrong otherwise it returns `false`
    storage: multer.diskStorage({ //this is our function that sets up where to store uploaded content on server, we have no control over its location but MongoDB has a default behavior of storing files in uploads/ directory within the database folder structure  so this allows us use as much space as necessary with only serving from storage
        destination: './uploads', //the place for multer to save your file. You can put it wherever you want, relative or absolute path is allowed here and MongoDB should have enough disk quota in the directory when storing files upladed by user there are some default paths mentioned below as well
        filename: function(req, file, cb) {  //this will be invoked with information about each uploaded image (such name or extension). The call back argument provides a callback and that's where you provide your customized save path. Multer can generate an unique id for every new upload if none provided
            var ext = path.extname(file.originalname); //getting file original name by the mime-type library from form data (morgane type of info about which part is actually in a multipart/form request) 
             cb(null, shortid.generate() + ext )   //this will be invoked with filename and extension together as parameter along to create your unique saved file name on server - using multer’s disk storage setting default settings from MongoDB for database storing files in upload directory of our project 
        }   
     })         
});      
const app = express(); //importing the Nodejs Expres application framework and then assign it to a variable so we can handle requests as Express apps. This is how you'll make use MongoDB by using multer middleware for handling file uploads  at /uploadendpoint on server side, which handles multipart/form-data in express app
app.post('/upload', upload.single('image'), (req, res) => { //we specify that we want to handle the image uploaded from a form named 'image' here and where multer should store it once done  then call back function of our configuration will be executed at /endpoint route
    if (!req.file) {   //check whether file is undefined or not, by default express uploads don’t include any additional information in the request object for uploaded files such as field name and filename so we check to see that they exist  then return a response back via res with message on what went wrong
        console.log('No File Selected');    //if nothing was selected, log an error but keep going if there is something happening within file uploading process at the server end using express middleware handling these type of request and responses in such cases you can use any catch block or default response message to be sent back from here.
        return res.status(501).send('No File Selected');  //sending a status code as error with this specific case, the user will get an appropriate feedback on what went wrong during file uploading process at server end using express middleware handling these type of request and responses in such cases you can use any catch block or default response message to be sent back from here.
    }  else {   //if a photo was uploaded successfully, log the filename it has been saved on your filesystem (relative path), then respond with success status code along them if there is no error at server end using express middleware handling these type of request and responses in such cases you can use any catch block or default response message to be sent back from here.
        console.log('File uploaded successfully');  //this will write a log on what has happened, so it's an easy way for debugging your app using NodeJs Console object which logs data into the JavaScript console with colorized output in different ways (default colors of NCConsole) - also you can do this by including these line inside catch block if any error occur at server end.
        res.status(201).send('File uploaded successfully');  //sending a status code as success along them when file upload is successful, with the name or path of saved image and on response back from here using express middleware handling these type of request-response in such cases you can use any catch block to be sent this feedback.
    }   });    
app.listen(3001); //the app will run at port 3001 with all server side operations set up and setup correctly from there onwards when expressjs framework is done executing the rest of these code snippets it'll start listening for requests made to its route ie - '/endpoint'.